static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

static bool controller_sensor_is_fresh(uint32_t now_ms, uint32_t last_ms)
{
    return (uint32_t) (now_ms - last_ms) <= CONTROLLER_SENSOR_TIMEOUT_MS;
}

static bool controller_has_fresh_temperature(const controller_t *controller, uint32_t now_ms)
{
    return (controller != NULL) && controller->has_valid_temperature && controller_sensor_is_fresh(now_ms, controller->last_temperature_ms);
}

static bool controller_has_fresh_level(const controller_t *controller, uint32_t now_ms)
{
    return (controller != NULL) && controller->has_valid_level && controller_sensor_is_fresh(now_ms, controller->last_level_ms);
}

static void controller_apply_safe_off(controller_t *controller)
{
    controller_set_safe_idle(controller);
}

static void controller_apply_policy(controller_t *controller, uint32_t now_ms)
{
    const int temperature_c = controller->last_temperature_c;
    const int level = controller->last_level;
    const bool temperature_rising = controller->has_previous_temperature && (controller->last_temperature_c > controller->previous_temperature_c);

    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_HOLDING;

    if (level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
        controller->inlet_open = true;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_FILLING;
        return;
    }

    if (level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
        controller->inlet_open = false;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_HOLDING;
        return;
    }

    if (level < CONTROLLER_MIN_HEATING_LEVEL) {
        controller->inlet_open = true;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_FILLING;
        return;
    }

    controller->inlet_open = false;

    if (temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_HOLDING;
        return;
    }

    if (temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
        controller->heater_on = true;
        controller->state = CONTROLLER_STATE_HEATING;
        return;
    }

    if ((temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) && (temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD) && temperature_rising) {
